# Definition for a Node.
class Node:
    def __init__(self, val=None, next=None):
        self.val = val
        self.next = next

class Solution:
    def insert(self, head: 'Node', insertVal: int) -> 'Node':
        # Your code here
        pass

def list_to_circular_linked_list(arr):
    if not arr:
        return None
    nodes = [Node(val) for val in arr]
    for i in range(len(nodes) - 1):
        nodes[i].next = nodes[i+1]
    nodes[-1].next = nodes[0] # Make it circular
    return nodes[0]

def circular_linked_list_to_list(head, max_len=10):
    if not head:
        return []
    result = []
    current = head
    for _ in range(max_len):
        result.append(current.val)
        current = current.next
        if current == head:
            break
    return result

s = Solution()
head_node = list_to_circular_linked_list([3,4,1])
result_head = s.insert(head_node, 2)
print(circular_linked_list_to_list(result_head)) # expected: [3,4,1,2] (order might vary, but elements should be present and sorted circularly)

